module d_ff_sync_reset(rst_clk, reset, d, q);

    input  rst_clk;  
    input  reset;  
    input  d;
    output  q;
    reg   q; 

    always @(posedge rst_clk)
          begin
            if (reset)
                q <= 0;
            else
                q <= d;
          end  

endmodule
